import { Component, OnInit, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './login.component.html',
  styleUrl: './login.component.css',
})
export class LoginComponent implements OnInit {
  private auth = inject(AuthService);
  private route = inject(ActivatedRoute);

  readonly errorMessage = signal<string>('');

  ngOnInit(): void {
    const params = this.route.snapshot.queryParamMap;
    const token = params.get('token');
    const error = params.get('error');

    if (token) {
      // OAuth callback: persist JWT, hydrate the session, then route to /feed.
      this.auth.completeOAuth(token);
      return;
    }

    if (error === 'denied') {
      this.errorMessage.set('LinkedIn sign-in was cancelled. Please try again to continue.');
    } else if (error === 'unavailable') {
      this.errorMessage.set('LinkedIn is temporarily unavailable — please try again in a moment.');
    }
  }

  signInWithLinkedIn(): void {
    this.auth.loginWithLinkedIn();
  }

  demoLogin(): void {
    this.auth.demoLogin();
  }
}
